import React from 'react';

const QuickActions = ({ setInputMessage, clearChat }) => {
  const quickActions = [
    { text: "Help with Python code 🐍", subject: "programming" },
    { text: "Solve math problem 📐", subject: "mathematics" },
    { text: "Explain science concept 🧬", subject: "science" },
    { text: "Literature analysis 📚", subject: "literature" }
  ];

  return (
    <div className="row">
      <div className="col-md-8 offset-md-2 col-lg-6 offset-lg-3">
        <div className="quick-actions">
          <div className="d-flex flex-wrap gap-2 justify-content-center mb-2">
            {quickActions.map((action, index) => (
              <button
                key={index}
                className="btn btn-outline-primary btn-sm quick-action-btn"
                onClick={() => setInputMessage(action.text)}
              >
                {action.text}
              </button>
            ))}
          </div>
          <div className="text-center">
            <button 
              className="btn btn-outline-light btn-sm"
              onClick={clearChat}
            >
              🔄 New Chat
            </button>
          </div>
        </div>
      </div>
    </div>
  );
};

export default QuickActions;
